  hanzo_hero_db: targets?.Hanzo?.detail_db || {},
  torbjorn_comp_db: targets?.Torbjorn?.comp_db || {},
  torbjorn_hero_db: targets?.Torbjorn?.detail_db || {},
  bastion_comp_db: targets?.Bastion?.comp_db || {},
