   target_selector: 'Soldier76 / Sojourn / Cassidy / Ashe / Reaper / Symmetra / Hanzo / Torbjorn / Bastion / Mei / Sombra / Tracer / Genji / Junkrat / Pharah / Echo / Emre',
   implemented_targets: targetHeroes.map(t => t.hero_id),
   version: root?.metadata?.version,
   public_release: root?.metadata?.display_version,
   data_layout: 'target_split_v20',
