 const jaTextMap = new WeakMap();
 function toEnglishText(input){
  let out = String(input||'');
  const trimmed = out.trim();
  if(UI_EXACT.has(trimmed)) return out.replace(trimmed, UI_EXACT.get(trimmed));
  if(PROSE_EXACT.has(trimmed)) return out.replace(trimmed, PROSE_EXACT.get(trimmed));
  if(PHASE7_EXACT.has(trimmed)) return out.replace(trimmed, PHASE7_EXACT.get(trimmed));
  for(const [rule,replacement] of PHASE7_REGEX_RULES){ out = out.replace(rule, replacement); }
  for(const [rule,replacement] of REGEX_RULES){ out = out.replace(rule, replacement); }
  for(const [ja,en] of PHRASES){ out = out.split(ja).join(en); }
  for(const [ja,en] of PHASE7_PHRASES){ out = out.split(ja).join(en); }
  for(const [rule,replacement] of PHASE7_POST_REGEX){ out = out.replace(rule, replacement); }
  out = out.replace(/（暫定）/g,' (Provisional)').replace(/、/g,', ').replace(/。/g,'.').replace(/：/g,': ').replace(/①/g,'1.').replace(/②/g,'2.').replace(/③/g,'3.').replace(/④/g,'4.').replace(/⑤/g,'5.').replace(/⑥/g,'6.').replace(/⑦/g,'7.');
  out = out.replace(/〜/g,'-').replace(/・/g,' / ').replace(/\s+,/g,',').replace(/,\s*,/g,',').replace(/\s+\./g,'.').replace(/\s{2,}/g,' ');
  out = out.replace(/([A-Za-z])する/g,'$1').replace(/([A-Za-z])した/g,'$1ed').replace(/checked/g,'checked').replace(/checkする/g,'check');
  return out;
 }
 
