    if(sub==='Specialist') return `${enemy} changes the map with setup tools. Clear the setup first instead of walking through it twice.`;
    if(sub==='Tactician') return `${enemy} wins by enabling the team. Track the setup window and punish during the reset.`;
    if(sub==='Medic') return `${enemy} keeps the fight alive. Force healing resources before committing to the final kill.`;
    if(sub==='Survivor') return `${enemy} is hard to finish cleanly. Bait the escape or save tool, then switch targets if the kill window closes.`;
