    if(t==='Genji') return `${name} should poke with ${primary}, force a defensive tool, then dash only when the reset or exit is clear. ${ult} needs cooldown tracking before the blade comes out.`;
    if(t==='Torbjorn') return `${name} should anchor space with Deploy Turret, punish enemies crossing open lanes, and use ${ult} to deny routes instead of chasing tanks.`;
    if(t==='Reaper') return `${name} should only take close fights when the exit is guaranteed. Force the enemy to look at you, then leave before the trade becomes a resource drain.`;
