    if(t==='Hanzo') return `${name} should gather information first, take one strong charged shot, then rotate. Do not stand in the open trying to out-duel ${threat}.`;
    if(t==='Ashe') return `${name} should control safe mid-to-long angles with ${primary} and Dynamite, then use B.O.B. to split attention or force enemies off cover.`;
