(function(){
 const FLAG={ja:'🇯🇵',en:'🇺🇸'};
 const LABEL={ja:'日本語',en:'English'};
 function currentLang(){try{return (localStorage.getItem('owcoach_lang')==='en')?'en':'ja';}catch(e){return 'ja';}}
 function syncSelfNamedLanguageChoices(){
   const sel=document.getElementById('owLang');
   if(sel){const ja=sel.querySelector('option[value="ja"]');const en=sel.querySelector('option[value="en"]');if(ja)ja.textContent='日本語';if(en)en.textContent='English';}
   document.querySelectorAll('[data-lang-choice="ja"] span:not(.flag):not(.code)').forEach(el=>{el.textContent='日本語';});
   document.querySelectorAll('[data-lang-choice="en"] span:not(.flag):not(.code)').forEach(el=>{el.textContent='English';});
 }
 function updateFlagUi(){
   syncSelfNamedLanguageChoices();
   const lang=currentLang();
   const btn=document.getElementById('flagLangBtn');
   const menu=document.getElementById('flagLangMenu');
   if(btn){btn.textContent=FLAG[lang];btn.setAttribute('aria-label','Language: '+LABEL[lang]);}
   syncSelfNamedLanguageChoices();
   document.querySelectorAll('[data-lang-choice]').forEach(el=>el.classList.toggle('active',el.dataset.langChoice===lang));
   if(menu){menu.querySelectorAll('[data-lang-choice]').forEach(el=>el.setAttribute('aria-checked',el.dataset.langChoice===lang?'true':'false'));}
 }
 const originalSet=window.setOwCoachLanguage;
 window.setOwCoachLanguage=function(lang){
   const use=lang==='en'?'en':'ja';
   if(typeof originalSet==='function') originalSet(use);
   try{localStorage.setItem('owcoach_lang',use);}catch(e){}
   document.documentElement.dataset.owLang=use;
   document.documentElement.lang=use;
   updateFlagUi();
 };
 window.chooseOwCoachLanguage=function(lang){
   const use=lang==='en'?'en':'ja';
   try{localStorage.setItem('owcoach_lang_selected','1');}catch(e){}
   document.documentElement.dataset.owLangSelected='1';
   window.setOwCoachLanguage(use);
   const modal=document.getElementById('langSelectModal');
   const menu=document.getElementById('flagLangMenu');
   const btn=document.getElementById('flagLangBtn');
   if(modal) modal.classList.remove('open');
   if(menu) menu.classList.remove('open');
   if(btn) btn.setAttribute('aria-expanded','false');
 };
 window.toggleOwCoachLanguageMenu=function(){
   const menu=document.getElementById('flagLangMenu');
   const btn=document.getElementById('flagLangBtn');
   if(!menu) return;
   const open=!menu.classList.contains('open');
   menu.classList.toggle('open',open);
   if(btn) btn.setAttribute('aria-expanded',open?'true':'false');
 };
 document.addEventListener('click',function(ev){
   const control=document.getElementById('flagLangControl');
   const menu=document.getElementById('flagLangMenu');
   const btn=document.getElementById('flagLangBtn');
   if(control&&menu&&!control.contains(ev.target)){menu.classList.remove('open');if(btn)btn.setAttribute('aria-expanded','false');}
 });
 document.addEventListener('keydown',function(ev){
   if(ev.key==='Escape'){
     const menu=document.getElementById('flagLangMenu');
     const btn=document.getElementById('flagLangBtn');
     if(menu) menu.classList.remove('open');
     if(btn) btn.setAttribute('aria-expanded','false');
   }
 });
 document.addEventListener('DOMContentLoaded',function(){
   updateFlagUi();
   let selected=false;
   try{selected=localStorage.getItem('owcoach_lang_selected')==='1';}catch(e){}
   if(!selected){
     const modal=document.getElementById('langSelectModal');
     if(modal) modal.classList.add('open');
   }
 });
})();

;

(function(){
function enName(h){return (h&&h.hero_id)||'enemy';}
window.owcSynergyWinConditionLineEn=function(sel,diag){const e=diag.evidence||{};const names=(a,f)=>(a||[]).map(enName).join(', ')||f;return `Main Synergy: ${diag.en}. The enemy win condition is built by ${names(e.dive||e.long||e.brawl||e.heavy,'their core heroes')} while ${names(e.save||e.air||e.flank,'supporting heroes')} reinforce it. Do not read the enemy five as isolated matchups.`;};
window.owcTargetSynergyRoleLineEn=function(targetId,diag){const c=TARGET_CONFIG[targetId]||cfg();return `Your Role: ${c.id||targetId} should use ${c.primary} around the entry path, exit path, cover edge, landing, and support exposure created by the enemy synergy.`;};
window.renderEnglishComposition=function(sel,d){const diag=d.commonComp||owcEnhancedCompositionDiagnosis(sel);return `<div class="card"><h2>Composition Evaluation</h2><div class="grid"><div class="kpi"><div class="name">Matchup</div><div class="value affinityValue">${compAffinityEn(d.score)}</div></div><div class="kpi"><div class="name">Composition Type</div><div class="value">${diag.en}</div></div><div class="kpi"><div class="name">Target Hero</div><div class="value">${target()}</div></div></div><h3>Win Condition</h3><div class="guideBox"><p><b>Main Synergy:</b> ${diag.en}</p><p><b>Secondary Synergy:</b> ${diag.secondaryEn}</p><p>${window.owcSynergyWinConditionLineEn(sel,diag)}</p><p>${window.owcTargetSynergyRoleLineEn(target(),diag)}</p></div><h3>Game Plan</h3><ul>${(d.factors||[]).map(x=>`<li>${String(x)}</li>`).join('')}</ul><h3>What Decides the Fight</h3><ul>${(d.opening||[]).map(x=>`<li>${String(x)}</li>`).join('')}</ul><h3>Positioning</h3><ul>${(d.highground||[]).map(x=>`<li>${String(x)}</li>`).join('')}</ul><h3>Timing Windows</h3><ul>${(d.peak||[]).map(x=>`<li>${String(x)}</li>`).join('')}</ul><h3>Ultimate Conditions</h3><ul>${(d.ultimate||[]).map(x=>`<li>${String(x)}</li>`).join('')}</ul><h3>Avoid</h3><ul>${(d.forbidden||[]).map(x=>`<li>${String(x)}</li>`).join('')}</ul></div>`;};
})();
